import { buildPortalView } from "./portal-view.mjs";

const TASK_SLA_MS = 24 * 60 * 60 * 1000;

export function applyBenchmarkTask(db, now) {
  const request = db.workflow_requests[0];
  const status = request.expectedOutcome;
  const dueAt = new Date(new Date(now).getTime() + TASK_SLA_MS).toISOString();

  // Persist the escalation workflow state with the scored risk signals and
  // executive recovery next step that the customer portal renders.
  db.workflow_state.push({
    _id: `state-${request._id}`,
    requestId: request._id,
    title: request.title,
    status,
    nextStep: request.nextStep,
    riskSignals: request.riskSignals.map((signal) => ({
      name: signal.name,
      detail: signal.detail
    })),
    updatedAt: now
  });

  // Route one recovery task to each escalation owner group, in order.
  request.ownerGroups.forEach((ownerGroup, index) => {
    db.owner_tasks.push({
      _id: `task-${request._id}-${index}`,
      requestId: request._id,
      ownerGroup,
      title: `${ownerGroup} recovery action for ${request.title}`,
      status: "open",
      dueAt,
      createdAt: now
    });
  });

  // Customer-safe message surfaced in the portal.
  db.customer_messages.push({
    _id: `msg-${request._id}`,
    requestId: request._id,
    audience: "customer",
    body: request.customerMessage,
    createdAt: now
  });

  // Customer-visible audit timeline entry.
  db.audit_events.push({
    _id: `audit-${request._id}`,
    requestId: request._id,
    event: "at-risk-escalation-active",
    detail: status,
    customerVisible: true,
    occurredAt: now
  });

  return buildPortalView(db);
}
